import { ipcMain, BrowserWindow } from 'electron';
import { z } from 'zod';
import { logger } from '../logger';
import { crashReportService } from '../services/CrashReportService';

const IPC_CHANNELS = {
  CRASH_REPORT_SUBMIT: 'crash-report:submit',
  CRASH_REPORT_DISMISS: 'crash-report:dismiss',
  CRASH_REPORT_HAS_PENDING: 'crash-report:has-pending',
  CRASH_REPORT_GET_PENDING: 'crash-report:get-pending',
  CRASH_REPORT_ADD_BREADCRUMB: 'crash-report:add-breadcrumb',
  CRASH_REPORT_CAPTURE_RENDERER_ERROR: 'crash-report:capture-renderer-error',
  CRASH_REPORT_SHOW_DIALOG: 'crash-report:show-dialog',
} as const;

const submitReportSchema = z.object({
  userComment: z.string().optional(),
});

const addBreadcrumbSchema = z.object({
  message: z.string(),
  category: z.string().optional(),
  data: z.record(z.string(), z.unknown()).optional(),
});

const captureRendererErrorSchema = z.object({
  message: z.string(),
  stack: z.string().optional(),
});

export function registerCrashReportHandlers() {
  // Submit crash report
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_SUBMIT, async (_event, args) => {
    try {
      const { userComment } = submitReportSchema.parse(args);
      const success = await crashReportService.submitCrashReport(userComment);

      return {
        success,
        data: { submitted: success },
        error: success ? undefined : 'Failed to submit crash report',
      };
    } catch (error) {
      logger.error('Error submitting crash report', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  // Dismiss crash report
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_DISMISS, async () => {
    try {
      crashReportService.dismissPendingCrash();
      return {
        success: true,
        data: { dismissed: true },
      };
    } catch (error) {
      logger.error('Error dismissing crash report', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  // Check if there's a pending crash
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_HAS_PENDING, async () => {
    try {
      const hasPending = crashReportService.hasPendingCrash();
      return {
        success: true,
        data: { hasPending },
      };
    } catch (error) {
      logger.error('Error checking for pending crash', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  // Get pending crash details
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_GET_PENDING, async () => {
    try {
      const crash = crashReportService.getPendingCrash();
      return {
        success: true,
        data: crash,
      };
    } catch (error) {
      logger.error('Error getting pending crash', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  // Add breadcrumb
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_ADD_BREADCRUMB, async (_event, args) => {
    try {
      const { message, category, data } = addBreadcrumbSchema.parse(args);
      crashReportService.addBreadcrumb(message, category, data);
      return {
        success: true,
        data: { added: true },
      };
    } catch (error) {
      logger.error('Error adding breadcrumb', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  // Capture renderer error and show dialog
  ipcMain.handle(IPC_CHANNELS.CRASH_REPORT_CAPTURE_RENDERER_ERROR, async (event, args) => {
    try {
      const { message, stack } = captureRendererErrorSchema.parse(args);
      const error = new Error(message);
      if (stack) {
        error.stack = stack;
      }

      // Capture the error
      crashReportService.captureError(error, {
        type: 'rendererError',
        timestamp: new Date().toISOString(),
      });

      // Notify renderer to show crash dialog
      const window = BrowserWindow.fromWebContents(event.sender);
      if (window && !window.isDestroyed()) {
        window.webContents.send(IPC_CHANNELS.CRASH_REPORT_SHOW_DIALOG);
      }

      return {
        success: true,
        data: { captured: true },
      };
    } catch (error) {
      logger.error('Error capturing renderer error', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      };
    }
  });

  logger.info('Crash report IPC handlers registered');
}
